  id: string;
  name: string;
  rate: number; // percentage
  active: boolean;
  type: 'SALES' | 'INCOME'; // SALES = Gross Up; INCOME = Profit Deduction
}

// --- CONFIGURAÇÃO CONTÁBIL (PLANO DE CONTAS) ---
export interface AccountingAccount {
    code: string; // ex: "3.1.01"
    name: string; // ex: "Receita Bruta de Serviços"
    type: 'CREDIT' | 'DEBIT';
}

export interface AccountingMapping {
    revenueAccount: AccountingAccount;
    deductionTaxesAccount: AccountingAccount; // Impostos s/ Venda
    directLaborAccount: AccountingAccount; // Salários
    laborChargesAccount: AccountingAccount; // Encargos
    laborProvisionsAccount: AccountingAccount; // Provisões (Férias/13o)
    operationalCostsAccount: AccountingAccount; // Materiais/EPIs
    safetyCostsAccount: AccountingAccount; // SMS
    supportCostsAccount: AccountingAccount; // Overhead
    marginAccount: AccountingAccount; // Lucro
    financialResultAccount: AccountingAccount; // Resultado Financeiro
}

export interface TaxConfig {
  regime: 'Lucro Real' | 'Lucro Presumido';
  calculationMode: 'NORMATIVE' | 'COMMERCIAL'; // NORMATIVE = Sales Tax only in Gross Up; COMMERCIAL = Sales + Income in Gross Up

  socialChargesRate: number;
  chargesBreakdown: {
    groupA: ChargeComponent[];
    groupB: ChargeComponent[];
    groupC: ChargeComponent[];
    groupD: ChargeComponent[];
  };

  salesTaxes: TaxItem[]; // PIS, COFINS, ISS, etc.
  incomeTaxes: TaxItem[]; // IRPJ, CSLL

  revenueTaxesRate: number; // Deprecated/Read-only sum
}

export interface ProposalDocuments {
  clientMemo: string; // O que o cliente pediu (informal)
  deliverables: string; // O que será entregue (formal)
  clientBudget?: number; // Target Price do cliente para Gap Analysis
  technicalAssumptions: string; // Premissas técnicas
  technicalNumber?: string; // Novo: Número da solicitação técnica
  attachments: Attachment[]; // Novo: Arquivos anexados
}

export type ProposalStatus = 'Draft' | 'Sent' | 'Negotiation' | 'Won' | 'Lost';

export type PricingModel = 'MARKUP' | 'MARGIN';

export interface ProposalData {
  id: string; // Internal UUID
  proposalId: string; // Human readable ID (e.g. 180256)
  version: number; // 1, 2, 3...
  createdAt: string;
  updatedAt: string;

  // New CRM Fields
  expirationDate: string; // Data de validade da proposta
  responsible: string; // Quem fez a precificação

  clientId?: string; // Link to Client Registry
  clientName: string; // Snapshot or fallback
  status: ProposalStatus;

  // CRM Data
  probability: number; // 0-100%
  value: number; // Snapshot of the total value

  // Pricing Data
  pricingModel?: PricingModel; // 'MARKUP' (Sobre Custo) ou 'MARGIN' (Sobre Venda/Numerador)
  markup: number; // Used for calculation (effective markup)
  targetMargin?: number; // Used for UI input when pricingModel === 'MARGIN'

  financialCostRate: number;
  contingencyRate: number;

  // --- PROJECT TIMELINE & FINANCE ---
  contractStartDate?: string; // Data de início do contrato (YYYY-MM-DD)
  mobilizationMonths: number; // Meses antes do início (ex: 1)
  contractDuration: number; // Padrão 12 meses

  paymentTermDays: number; // Prazo de recebimento (ex: 30, 45, 60)
  supplierPaymentTermDays: number; // Prazo médio pagto fornecedores
  payrollCashFlowDay: number; // Dia do mês para pagamento de folha (ex: 5)

  wacc: number; // Weighted Average Cost of Capital (TMA do Projeto) anual

  // --- LOCAL OVERRIDES ---
  issTaxOverride?: number; // Se definido, substitui a taxa de ISS global (ex: 0.02)

  roles: Role[];
  sections?: CanvasSection[]; // New: Background Areas/Lanes

  expenses: ExpenseItem[];

  // Novos Arrays de Custo
  safetyCosts: SafetyItem[]; // NRs, Treinamentos
  supportCosts: SupportItem[]; // Overhead, Visitas de Gestão

  // Configuração de Kits (Geralmente preenchido apenas no GlobalConfig)
  kitTemplates?: KitTemplate[];

  taxConfig: TaxConfig;

  // Configuração Contábil Global (Injetada)
  accountingConfig?: AccountingMapping;

  // Documentation & Analysis
  documents: ProposalDocuments;
}

export interface CalculatedFinancials {
  totalLaborCost: number;
  totalOperationalCost: number; // Materiais e Despesas
  totalSafetyCost: number; // Novo: Treinamentos e Exames
  totalSupportCost: number; // Novo: Overhead de Gestão

  totalDirectCost: number; // Soma de tudo acima

  totalIndirectCost: number; // Financial + Contingency
  totalCostBase: number; // Direct + Indirect

  markupAmount: number; // Result. Operacional (Contábil Final)
  netRevenue: number; // Preço sem impostos
  grossRevenue: number; // Preço Final

  // --- NEW FIELDS ---
  operationalProfitAmount: number; // EBITDA (Lucro Operacional antes de Fin/IR)
  operationalMarginPercent: number; // % da Margem Operacional sobre Venda Bruta

  salesTaxAmount: number; // Impostos da Nota
  incomeTaxAmount: number; // Estimativa de IRPJ/CSLL

  grossMarginPercent: number; // Margem Contábil
  netProfitAmount: number; // Resultado Líquido Final Estimado
  netProfitPercent: number; 

  monthlyValue: number;
  annualValue: number;
}

import { ProposalData, CalculatedFinancials, AccountingMapping } from '../types';

/**
 * Biblioteca de Matemática Financeira Segura (Integer Math)
 * Política B: Arredondamento em cada etapa monetária (2 casas)
 */
const PricingMath = {
  // Arredonda um float para 2 casas decimais de forma segura
  round: (value: number): number => {
    return Math.round((value + Number.EPSILON) * 100) / 100;
  },

  // Multiplica Valor * Taxa e arredonda o resultado imediatamente
  // Ex: 100.00 * 0.1633 = 16.33
  multiply: (value: number, rate: number): number => {
    return PricingMath.round(value * rate);
  },

  // Soma segura
  add: (a: number, b: number): number => {
    return PricingMath.round(a + b);
  },

  // Gross Up: Net / (1 - Tax)
  grossUp: (netValue: number, taxRate: number): number => {
    const divisor = 1 - taxRate;
    if (divisor <= 0.0001) return netValue; // Evita divisão por zero
    return PricingMath.round(netValue / divisor);
  }
};

export interface ExtendedFinancials extends CalculatedFinancials {
  contingencyAmount: number;
  financialCostAmount: number;
  totalCostWithContingency: number;
  revenueDeductionsAmount: number;
  effectiveIssRate?: number;
}

export const calculateFinancials = (data: ProposalData): ExtendedFinancials => {
  // --- 0. MARKUP EFFECTIVE RATE LOGIC ---
  // Se o modelo for por MARGEM, converte a margem alvo em markup equivalente.
  // Formula: Markup = Margem / (1 - Margem)
  let effectiveMarkupRate = data.markup;

  if (data.pricingModel === 'MARGIN' && data.targetMargin !== undefined) {
      // Evita divisão por zero se a margem for 100%
      const safeMargin = Math.min(data.targetMargin, 0.9999); 
      effectiveMarkupRate = safeMargin / (1 - safeMargin);
  }

  // 1. Custo de Mão de Obra (Etapa a Etapa)
  let totalLaborCost = 0;

  data.roles.forEach(role => {
    let baseSalary = role.baseSalary;
    let addOns = 0;

    // Adicionais (Insalubridade/Periculosidade) incidem sobre o base e são arredondados
    if (role.additionalHazard) addOns += PricingMath.multiply(baseSalary, 0.20);
    if (role.additionalDanger) addOns += PricingMath.multiply(baseSalary, 0.30);

    const unitBase = PricingMath.add(baseSalary, addOns);
    const unitCharges = PricingMath.multiply(unitBase, data.taxConfig.socialChargesRate);
    const unitTotalCost = PricingMath.add(unitBase, unitCharges);

    // Multiplica pela quantidade e soma ao total
    totalLaborCost = PricingMath.add(totalLaborCost, unitTotalCost * role.quantity);
  });

  // HC Operacional para rateios
  const operationalHeadcount = data.roles
    .filter(r => r.category === 'Operational')
    .reduce((acc, r) => acc + r.quantity, 0);

  // 2. Despesas Operacionais (Materiais, EPIs, etc.)
  let totalOperationalCost = 0;
  data.expenses.forEach(exp => {
    const months = exp.lifespan > 0 ? exp.lifespan : 1;
    // Amortização mensal (mantemos precisão aqui pois é uma taxa interna)
    const monthlyAmortization = exp.unitPrice / months; 

    const quantity = exp.allocation === 'PerHead' ? operationalHeadcount : 1;
    // Arredondamos apenas o valor final da linha de despesa
    const itemTotal = PricingMath.round(monthlyAmortization * quantity);

    totalOperationalCost = PricingMath.add(totalOperationalCost, itemTotal);
  });

  // 3. Custos de Segurança (NRs - Treinamentos/Exames)
  let totalSafetyCost = 0;
  (data.safetyCosts || []).forEach(item => {
      if (item.active) {
          const months = item.frequencyMonths > 0 ? item.frequencyMonths : 12;
          const monthlyAmortization = item.costPerHead / months;
          const itemTotal = PricingMath.round(monthlyAmortization * operationalHeadcount);
          totalSafetyCost = PricingMath.add(totalSafetyCost, itemTotal);
      }
  });

  // 4. Custos de Suporte (Overhead Operacional)
  let totalSupportCost = 0;
  (data.supportCosts || []).forEach(item => {
      const itemTotal = PricingMath.round(item.costPerVisit * item.quantity);
      totalSupportCost = PricingMath.add(totalSupportCost, itemTotal);
  });

  // 5. Custos Diretos Totais (CD)
  const totalDirectCost = PricingMath.add(
      PricingMath.add(totalLaborCost, totalOperationalCost),
      PricingMath.add(totalSafetyCost, totalSupportCost)
  );

  // --- NOVA LÓGICA DE BDI (Híbrida) ---

  // A. CONTINGÊNCIA (Sobre o Custo Direto)
  // Agora tratada como um "Add-on" ao custo, inflacionando a base para o Markup.
  const contingencyAmount = PricingMath.multiply(totalDirectCost, data.contingencyRate);
  const totalCostWithContingency = PricingMath.add(totalDirectCost, contingencyAmount);

  // B. NUMERADOR (Custo Inflado + Lucro)
  // O Markup é aplicado sobre o (Custo Direto + Contingência)
  const markupAmountTarget = PricingMath.multiply(totalCostWithContingency, effectiveMarkupRate);
  const numerator = PricingMath.add(totalCostWithContingency, markupAmountTarget);

  // C. DIVISOR (Impostos + Custo Financeiro)
  // Custo Financeiro permanece como dedução da receita (Taxa sobre Venda Bruta)

  // Tax Override Logic (ISS)
  let effectiveSalesTaxes = data.taxConfig.salesTaxes;

  // If override exists, replace the ISS item or add/adjust it
  if (data.issTaxOverride !== undefined && data.issTaxOverride >= 0) {
      effectiveSalesTaxes = data.taxConfig.salesTaxes.map(t => {
          if (t.id === 'iss') return { ...t, rate: data.issTaxOverride! };
          return t;
      });
  }

  const activeSalesRate = effectiveSalesTaxes
    .filter(t => t.active)
    .reduce((acc, t) => acc + t.rate, 0);

  const activeIncomeRate = data.taxConfig.incomeTaxes
    .filter(t => t.active)
    .reduce((acc, t) => acc + t.rate, 0);

  // Impostos Totais no Divisor
  let taxesInDivisor = activeSalesRate;
  if (data.taxConfig.calculationMode === 'COMMERCIAL') {
    taxesInDivisor += activeIncomeRate;
  }

  // Custo Financeiro entra aqui para garantir Gross Up correto
  const revenueDeductionsRate = data.financialCostRate;

  const totalDivisorRate = taxesInDivisor + revenueDeductionsRate;

  // D. Cálculo do Preço Final (Gross Revenue)
  // Preço = (Custo + Contingencia + Lucro) / (1 - (Impostos + Financeiro))
  const grossRevenue = PricingMath.grossUp(numerator, totalDivisorRate);

  // E. Cálculo Reverso dos Valores Absolutos (Para o Waterfall)
  const financialCostAmount = PricingMath.multiply(grossRevenue, data.financialCostRate);
  const salesTaxAmount = PricingMath.multiply(grossRevenue, activeSalesRate);

  // Total Deduções da Receita (Para exibição no Waterfall)
  let revenueDeductionsAmount = PricingMath.add(salesTaxAmount, financialCostAmount);

  let incomeTaxAmount = 0;
  if (data.taxConfig.calculationMode === 'NORMATIVE') {
    // Estimativa sobre o lucro operacional (apenas informativo)
    incomeTaxAmount = PricingMath.multiply(markupAmountTarget, activeIncomeRate); 
  } else {
    // Modo Comercial: IR está no preço
    incomeTaxAmount = PricingMath.multiply(grossRevenue, activeIncomeRate);
    revenueDeductionsAmount = PricingMath.add(revenueDeductionsAmount, incomeTaxAmount);
  }

  // Custo Indireto Total (Para compatibilidade de tipos, soma Contingencia + Financeiro)
  const totalIndirectCost = PricingMath.add(contingencyAmount, financialCostAmount);
  const totalCostBase = PricingMath.add(totalDirectCost, totalIndirectCost);

  // F. Resultado Operacional Real (Markup Real - Contábil)
  const netRevenue = PricingMath.add(grossRevenue, -salesTaxAmount);

  // Cálculo do Lucro Contábil
  let markupAmount = grossRevenue;
  markupAmount -= salesTaxAmount;
  markupAmount -= financialCostAmount;
  if (data.taxConfig.calculationMode === 'COMMERCIAL') markupAmount -= incomeTaxAmount;
  markupAmount -= contingencyAmount;
  markupAmount -= totalDirectCost;
  markupAmount = PricingMath.round(markupAmount);

  // G. MARGEM OPERACIONAL (EBITDA Proxy)
  // Receita Liquida - (Custos Diretos + Contingencia)
  // Contingência é considerada custo operacional indireto aqui.
  // Não subtrai Financeiro e nem IRPJ.
  let operationalProfitAmount = netRevenue;
  operationalProfitAmount -= totalDirectCost;
  operationalProfitAmount -= contingencyAmount;
  operationalProfitAmount = PricingMath.round(operationalProfitAmount);

  const operationalMarginPercent = grossRevenue > 0 ? (operationalProfitAmount / grossRevenue) * 100 : 0;

  // KPIs Finais
  const grossMarginPercent = grossRevenue > 0 ? (markupAmount / grossRevenue) * 100 : 0;

  let netProfitAmount = markupAmount;
  if (data.taxConfig.calculationMode === 'NORMATIVE') {
      netProfitAmount = PricingMath.add(markupAmount, -incomeTaxAmount);
  }

  const netProfitPercent = grossRevenue > 0 ? (netProfitAmount / grossRevenue) * 100 : 0;

  return {
    totalLaborCost,
    totalOperationalCost,
    totalSafetyCost,
    totalSupportCost,
    totalDirectCost,
    contingencyAmount, 
    financialCostAmount,
    totalCostWithContingency,
    revenueDeductionsAmount,
    totalIndirectCost, 
    totalCostBase,
    markupAmount,
    netRevenue,
    grossRevenue,

    // New Fields
    operationalProfitAmount,
    operationalMarginPercent,

    salesTaxAmount,
    incomeTaxAmount,
    grossMarginPercent,
    netProfitAmount,
    netProfitPercent,
    monthlyValue: grossRevenue,
    annualValue: grossRevenue * 12,
    effectiveIssRate: data.issTaxOverride
  };
};

export const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'currency',
    currency: 'BRL',
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
};

export const formatPercent = (value: number) => {
  return new Intl.NumberFormat('pt-BR', {
    style: 'percent',
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  }).format(value);
};


// --- FINANCIAL PROJECTIONS (DRE & CASH FLOW) ---

export interface FinancialMonth {
  monthIndex: number; // -X (Mob), 0 (Mês 1)...
  label: string; // "Mob -1", "Mês 1", "Mês 2"
  date: string; // YYYY-MM

  // DRE (Regime de Competência - Quando o fato ocorre)
  dre: {
      grossRevenue: number;
      deductionTaxes: number;
      netRevenue: number;
      directLabor: number;
      operationalCosts: number;
      safetyCosts: number;
      supportCosts: number;
      grossProfit: number;
      indirectCosts: number; // Contingency/Risk
      ebitda: number;
      financialResult: number; // Expense
      ebt: number;
      taxesOnProfit: number;
      netIncome: number;
  };

  // CASH FLOW (Regime de Caixa - Quando o dinheiro entra/sai)
  cashFlow: {
      inflow: number; // Recebimentos
      outflowLabor: number; // Salários
      outflowTaxes: number; // Impostos
      outflowSuppliers: number; // Fornecedores
      outflowFinancial: number; // Juros Pagos
      totalOutflow: number;
      netCash: number;
      cumulativeCash: number;
  };
}

export interface FinancialProjection {
  timeline: FinancialMonth[];
  indicators: {
    paybackMonth: number; // Month index where cumulative cash becomes positive
    npv: number; // Net Present Value (VPL)
    irr: number; // Internal Rate of Return (TIR)
    totalInvestment: number; // Max negative cash flow (Exposição de Caixa)
    roi: number; // Return on Investment %
  }
}

// Helper: Calculate IRR using Newton-Raphson approximation
const calculateIRR = (cashFlows: number[], guess = 0.1): number => {
    // CRITICAL FIX: Ensure cash flows have at least one positive and one negative value
    // Without this, the algorithm will not converge and return infinite or NaN
    const hasPositive = cashFlows.some(v => v > 0);
    const hasNegative = cashFlows.some(v => v < 0);

    if (!hasPositive || !hasNegative) {
        return 0; // Return 0 if IRR cannot be mathematically determined
    }

    const maxIterations = 1000;
    const tolerance = 0.00001;

    let rate = guess;

    for (let i = 0; i < maxIterations; i++) {
        let npv = 0;
        let dNpv = 0; // Derivative of NPV with respect to rate

        for (let t = 0; t < cashFlows.length; t++) {
            const factor = Math.pow(1 + rate, t);
            npv += cashFlows[t] / factor;
            dNpv -= (t * cashFlows[t]) / (factor * (1 + rate));
        }

        // Prevent division by zero
        if (Math.abs(dNpv) < 0.0000001) {
            return 0;
        }

        const newRate = rate - npv / dNpv;

        if (Math.abs(newRate - rate) < tolerance) {
            if (!isFinite(newRate) || isNaN(newRate)) return 0;
            return newRate;
        }

        rate = newRate;
    }

    return 0; // Did not converge
};

export const generateFinancialProjections = (data: ProposalData, accountingConfig?: AccountingMapping): FinancialProjection => {
    const financials = calculateFinancials(data);
    const months: FinancialMonth[] = [];

    // Parameters
    const mobilizationMonths = data.mobilizationMonths || 1;
    const contractDuration = data.contractDuration || 12;
    const paymentTermDays = data.paymentTermDays || 30; // Recebimento Cliente
    const supplierTermDays = data.supplierPaymentTermDays || 30; // Pagto Fornecedor
    // Default WACC to 12% if not set
    const discountRateAnnual = data.wacc || 0.12; 
    const discountRateMonthly = Math.pow(1 + discountRateAnnual, 1/12) - 1; 

    // Convert terms to monthly lags (simplified for grid projection)
    const receiptLag = Math.ceil(paymentTermDays / 30); 
    const supplierLag = Math.ceil(supplierTermDays / 30);
    // Labor is paid on day X. If day < 30, it's next month (Lag 1). 
    // Usually salaries for month M are paid in M+1 (e.g. 5th day).
    const laborLag = 1; 
    // Taxes usually paid next month (20th), so Lag = 1
    const taxLag = 1;

    let cumulativeCash = 0;
    let minCash = 0;

    // Timeline Loop: From Mobilization start (-Mob) to Contract End + Lags
    // We extend the loop to cover the cash flow tail (receivables coming after contract ends)
    const maxTimeline = contractDuration + receiptLag + 1;

    // Date Management
    const startDate = data.contractStartDate ? new Date(data.contractStartDate) : new Date();
    // Adjust start date to account for mobilization (shift back)
    const projectStartDate = new Date(startDate);
    projectStartDate.setMonth(projectStartDate.getMonth() - mobilizationMonths);

    for (let i = -mobilizationMonths; i < maxTimeline; i++) {
        const isMobilization = i < 0;
        const isContractPeriod = i >= 0 && i < contractDuration;

        let monthLabel = '';
        if (isMobilization) monthLabel = `Mob ${i + mobilizationMonths + 1}`;
        else if (i < contractDuration) monthLabel = `Mês ${i + 1}`;
        else monthLabel = `Pós ${i - contractDuration + 1}`;

        // Calculate Date for this index
        const currentDate = new Date(projectStartDate);
        currentDate.setMonth(currentDate.getMonth() + (i + mobilizationMonths));
        const dateStr = currentDate.toLocaleDateString('pt-BR', { month: 'short', year: '2-digit' });

        // --- 1. DRE (COMPETÊNCIA) ---
        // Acontece apenas durante o período do contrato (0 a Duration-1) e Mobilização

        const hasRevenue = isContractPeriod;

        // Na mobilização, assumimos custos de Setup (ex: 60% do custo mensal regular como estimativa de contratação/treinamento/compras)
        // Em um sistema real, teríamos um "Budget de Mobilização" separado.
        const opFactor = isMobilization ? 0.6 : (isContractPeriod ? 1.0 : 0);

        const dre = {
            grossRevenue: hasRevenue ? financials.monthlyValue : 0,
            deductionTaxes: hasRevenue ? financials.salesTaxAmount : 0,
            netRevenue: hasRevenue ? financials.netRevenue : 0,

            directLabor: financials.totalLaborCost * opFactor,
            operationalCosts: financials.totalOperationalCost * opFactor,
            safetyCosts: financials.totalSafetyCost * opFactor,
            supportCosts: financials.totalSupportCost * opFactor,

            get grossProfit() { return this.netRevenue - (this.directLabor + this.operationalCosts + this.safetyCosts + this.supportCosts) },

            indirectCosts: (financials.contingencyAmount) * opFactor,

            get ebitda() { return this.grossProfit - this.indirectCosts },

            // Custo Financeiro (Juros) é uma despesa na competência se estamos financiando
            financialResult: hasRevenue ? -financials.financialCostAmount : 0,

            get ebt() { return this.ebitda + this.financialResult },

            taxesOnProfit: hasRevenue ? financials.incomeTaxAmount : 0,

            get netIncome() { return this.ebt - this.taxesOnProfit }
        };

        // --- 2. CASH FLOW (CAIXA) ---
        // Baseado nos Lags sobre os valores do DRE dos meses anteriores

        // Helper to get DRE value from month X
        const getMonthDRE = (targetIndex: number) => {
            // Logic duplicated implies constant monthly values during contract
            if (targetIndex >= 0 && targetIndex < contractDuration) return { ...financials, opFactor: 1 };
            if (targetIndex >= -mobilizationMonths && targetIndex < 0) return { ...financials, monthlyValue: 0, salesTaxAmount: 0, opFactor: 0.6 };
            return { monthlyValue: 0, salesTaxAmount: 0, totalLaborCost: 0, totalOperationalCost: 0, totalSafetyCost: 0, totalSupportCost: 0, opFactor: 0, incomeTaxAmount: 0, financialCostAmount: 0, contingencyAmount: 0 };
        };

        // Inflow: Revenue from (i - receiptLag)
        const revenueSourceMonth = i - receiptLag;
        const inflow = (revenueSourceMonth >= 0 && revenueSourceMonth < contractDuration) ? financials.monthlyValue : 0;

        // Outflows
        const laborSource = getMonthDRE(i - laborLag);
        const outflowLabor = laborSource.totalLaborCost * laborSource.opFactor;

        const taxSource = getMonthDRE(i - taxLag);
        const outflowTaxes = (taxSource.salesTaxAmount + taxSource.incomeTaxAmount) * (taxSource.monthlyValue > 0 ? 1 : 0); // Only if revenue existed

        const supplierSource = getMonthDRE(i - supplierLag);
        const supplierCosts = (supplierSource.totalOperationalCost + supplierSource.totalSafetyCost + supplierSource.totalSupportCost + supplierSource.contingencyAmount) * supplierSource.opFactor;
        const outflowSuppliers = supplierCosts;

        // Financial Cost (Interest paid on loans) - Assumed paid monthly
        const financialSource = getMonthDRE(i);
        const outflowFinancial = financialSource.financialCostAmount * (financialSource.monthlyValue > 0 ? 1 : 0);

        const totalOutflow = outflowLabor + outflowTaxes + outflowSuppliers + outflowFinancial;
        const netCash = inflow - totalOutflow;

        cumulativeCash += netCash;
        if (cumulativeCash < minCash) minCash = cumulativeCash;

        months.push({
            monthIndex: i,
            label: monthLabel,
            date: dateStr,
            dre,
            cashFlow: {
                inflow,
                outflowLabor,
                outflowTaxes,
                outflowSuppliers,
                outflowFinancial,
                totalOutflow,
                netCash,
                cumulativeCash
            }
        });
    }

    // --- INDICATORS ---

    // Payback: First month where cumulative cash > 0
    const paybackMonthData = months.find(m => m.cashFlow.cumulativeCash >= 0 && m.monthIndex >= 0);
    const paybackMonth = paybackMonthData ? paybackMonthData.monthIndex + 1 : 0;

    // VPL (NPV)
    let npv = 0;
    const netCashFlows: number[] = [];

    // Normalize t=0 to first mobilization month
    months.forEach((m, index) => {
        npv += m.cashFlow.netCash / Math.pow(1 + discountRateMonthly, index);
        netCashFlows.push(m.cashFlow.netCash);
    });

    // TIR (IRR)
    const irrMonthly = calculateIRR(netCashFlows);
    const irrAnnual = Math.pow(1 + irrMonthly, 12) - 1;

    // ROI
    const totalProfit = months.reduce((acc, m) => acc + m.dre.netIncome, 0);
    const roi = (Math.abs(minCash) > 0.01) ? (totalProfit / Math.abs(minCash)) * 100 : 0;

    return {
        timeline: months,
        indicators: {
            paybackMonth,
            npv,
            irr: irrAnnual,
            totalInvestment: Math.abs(minCash),
            roi
        }
    };
};

