                        <tbody className="text-xs">
                            {rowDefinitions.map((row, idx) => {
                                const values = getRowData(row.key);
                                const total = values.reduce((acc, v) => acc + v, 0);
                                const isNegative = total < -0.01;

                                // Styling Logic
                                const isTotal = row.type === 'total';
                                const isFinal = row.type === 'final';
                                const isSubtotal = row.type === 'subtotal';
                                const isItem = row.type === 'item';

                                // Base row styling
                                let rowClass = "border-b border-slate-50 hover:bg-slate-50 transition-colors group";

                                // Sticky Cell Colors (Must be fully opaque to cover scrolled content)
                                let stickyBg = "bg-white"; 
                                let stickyText = "text-slate-600";
                                let stickyBorder = "border-slate-100";

                                if (isFinal) {
                                    rowClass = "bg-[#0f172a] text-white hover:bg-[#1e293b]";
                                    stickyBg = "bg-[#0f172a]";
                                    stickyText = "text-white";
                                    stickyBorder = "border-slate-700";
                                } else if (isTotal) {
                                    rowClass = "bg-blue-50/50 text-blue-900 font-bold border-y border-blue-100 hover:bg-blue-100/50";
                                    stickyBg = "bg-blue-50";
                                    stickyText = "text-blue-900";
                                    stickyBorder = "border-blue-200";
                                } else if (isSubtotal) {
                                    rowClass = "bg-slate-50 font-bold border-y border-slate-200 hover:bg-slate-100";
                                    stickyBg = "bg-slate-50";
                                    stickyText = "text-slate-800";
                                    stickyBorder = "border-slate-200";
                                }

                                return (
                                    <tr key={idx} className={rowClass}>
                                        {/* Sticky Columns Data (Z-Index ensures they stay on top) */}
                                        <td style={stickyStyle.col1} className={`sticky z-40 px-3 py-3 text-left font-mono text-[10px] border-r ${stickyBg} ${stickyText} ${stickyBorder}`}>
                                            {row.code}
                                        </td>
                                        <td style={stickyStyle.col2} className={`sticky z-40 px-3 py-3 text-left font-medium border-r ${stickyBg} ${stickyText} ${stickyBorder}`}>
                                            {row.label}
                                        </td>
                                        <td style={stickyStyle.col3} className={`sticky z-30 px-3 py-3 text-right font-bold tabular-nums border-r shadow-[4px_0_8px_-4px_rgba(0,0,0,0.1)] ${isFinal ? 'bg-[#1e293b] text-[#fbbf24] border-slate-700' : isTotal ? 'bg-blue-100/50 text-blue-900 border-blue-200' : 'bg-slate-50 text-slate-900 border-slate-300'}`}>
                                            <span className={row.inverse && isNegative ? (isFinal ? 'text-red-400' : 'text-red-600') : ''}>
                                                {formatCurrency(total)}
                                            </span>
                                        </td>

                                        {/* Scrollable Data */}
                                        <td className="px-1 py-1 text-center min-w-[80px]">
                                             <div className="flex justify-center h-6 w-full">
                                                <Sparkline 
                                                    data={values} 
                                                    width={60} 
                                                    height={20} 
                                                    color={isFinal ? '#fbbf24' : isTotal ? '#2563eb' : isNegative ? '#ef4444' : '#64748b'} 
                                                />
                                             </div>
                                        </td>

                                        {values.map((v, i) => {
                                            const valIsNeg = v < -0.01;
                                            return (
                                                <td key={i} className="px-4 py-2 tabular-nums whitespace-nowrap">
                                                    <span className={row.inverse && valIsNeg ? (isFinal ? 'text-red-400' : 'text-red-600') : (Math.abs(v) < 0.01 ? 'opacity-30' : '')}>
                                                        {Math.abs(v) < 0.01 ? '-' : formatCurrency(v)}
                                                    </span>
                                                </td>
                                            );
                                        })}
                                    </tr>
                                );
                            })}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
  };

  const renderCashFlow = () => (
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8 flex flex-col items-center justify-center min-h-[400px]">
          <Activity size={48} className="text-slate-300 mb-4" />
          <h3 className="text-lg font-bold text-slate-700">Fluxo de Caixa</h3>
          <p className="text-slate-500 text-sm mb-6 max-w-md text-center">
              Visualização de entradas e saídas financeiras baseadas nos prazos de pagamento configurados.
          </p>
          <div className="w-full max-w-5xl overflow-hidden rounded-lg border border-slate-200">
               {/* Simplified Cashflow Table for brevity in this specific task update */}
               <div className="p-4 bg-slate-50 text-center text-sm font-medium text-slate-500">
                   Gráfico de Fluxo de Caixa (Em Desenvolvimento)
               </div>
          </div>
      </div>
  );

  return (
    <div className="p-8 space-y-8 max-w-[100vw] overflow-x-hidden">
      {/* Header with Navigation */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6 border-b border-slate-200 pb-6">
          <div>
              <h2 className="text-3xl font-bold text-slate-800 flex items-center gap-3">
                  <PieChart size={32} className="text-[#0f172a]" />
                  Dashboard Financeiro
              </h2>
              <p className="text-slate-500 mt-1">Análise de viabilidade: {data.clientName} (#{data.proposalId})</p>
          </div>

          <div className="flex bg-slate-100 p-1 rounded-xl shadow-inner">
              {[
                  { id: 'summary', label: 'Resumo Executivo', icon: LayoutTemplate },
                  { id: 'cashflow', label: 'Fluxo de Caixa', icon: ArrowUpRight },
                  { id: 'dre', label: 'DRE / Orçamento', icon: BookOpen },
                  { id: 'feasibility', label: 'Viabilidade Econômica', icon: Coins },
              ].map(tab => {
                  const Icon = tab.icon;
                  return (
                    <button 
                        key={tab.id}
                        onClick={() => setActiveView(tab.id as any)}
                        className={`px-4 py-2.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${activeView === tab.id ? 'bg-white shadow text-[#0f172a] ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'}`}
                    >
                        <Icon size={14} />
                        {tab.label}
                    </button>
                  );
              })}
          </div>
      </div>

      {/* Main Content Render */}
      <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
          {activeView === 'summary' && renderSummary()}
          {activeView === 'dre' && renderDRE()}
          {activeView === 'cashflow' && renderCashFlow()}
          {activeView === 'feasibility' && (
              <div className="p-8 bg-white border border-slate-200 rounded-xl">
                  <h3 className="font-bold text-lg mb-4">Indicadores de Viabilidade</h3>
                  <div className="grid grid-cols-4 gap-6">
                      <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                          <p className="text-xs uppercase font-bold text-slate-400">VPL (Net Present Value)</p>
                          <p className="text-2xl font-bold text-slate-800">{formatCurrency(projections.indicators.npv)}</p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                          <p className="text-xs uppercase font-bold text-slate-400">TIR (IRR)</p>
                          <p className="text-2xl font-bold text-slate-800">{formatPercent(projections.indicators.irr)}</p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                          <p className="text-xs uppercase font-bold text-slate-400">Payback</p>
                          <p className="text-2xl font-bold text-slate-800">{projections.indicators.paybackMonth} meses</p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                          <p className="text-xs uppercase font-bold text-slate-400">Investimento Máximo</p>
                          <p className="text-2xl font-bold text-red-600">{formatCurrency(projections.indicators.totalInvestment)}</p>
                      </div>
                  </div>
              </div>
          )}
      </div>

    </div>
  );
};

