// Sparkline Component para visualização de tendência
const Sparkline: React.FC<{ data: number[], color?: string, height?: number, width?: number }> = ({ data, color = "#64748b", height = 24, width = 60 }) => {
    if (!data || data.length < 2) return <div style={{width, height}} className="opacity-10"></div>;

    const min = Math.min(...data);
    const max = Math.max(...data);
    const range = max - min || 1;
    const step = width / (data.length - 1);

    // Build path
    const points = data.map((val, i) => {
        const x = i * step;
        const normalizedY = ((val - min) / range); 
        // Invert Y because SVG 0 is top
        const y = height - (normalizedY * height); 
        return `${x},${y}`;
    }).join(' ');

    return (
        <svg width={width} height={height} className="overflow-visible">
            <polyline 
                points={points} 
                fill="none" 
                stroke={color} 
                strokeWidth="1.5" 
                strokeLinecap="round" 
                strokeLinejoin="round" 
                className="opacity-80"
            />
            {/* End dot */}
            <circle cx={width} cy={height - ((data[data.length-1] - min)/range * height)} r="2" fill={color} />
        </svg>
    );
};

