                  return (
                    <button 
                        key={tab.id}
                        onClick={() => setActiveView(tab.id as any)}
                        className={`px-4 py-2.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${activeView === tab.id ? 'bg-white shadow text-[#0f172a] ring-1 ring-black/5' : 'text-slate-500 hover:text-slate-700 hover:bg-slate-200/50'}`}
                    >
                        <Icon size={14} />
                        {tab.label}
                    </button>
                  );
              })}
          </div>
      </div>

      {/* Main Content Render */}
      <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
          {activeView === 'summary' && renderSummary()}
          {activeView === 'dre' && renderDRE()}
          {activeView === 'cashflow' && renderCashFlow()}
          {activeView === 'feasibility' && (
              <div className="p-8 bg-white border border-slate-200 rounded-xl">
                  <h3 className="font-bold text-lg mb-4">Indicadores de Viabilidade</h3>
                  <div className="grid grid-cols-4 gap-6">
                      <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                          <p className="text-xs uppercase font-bold text-slate-400">VPL (Net Present Value)</p>
                          <p className="text-2xl font-bold text-slate-800">{formatCurrency(projections.indicators.npv)}</p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                          <p className="text-xs uppercase font-bold text-slate-400">TIR (IRR)</p>
                          <p className="text-2xl font-bold text-slate-800">{formatPercent(projections.indicators.irr)}</p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                          <p className="text-xs uppercase font-bold text-slate-400">Payback</p>
                          <p className="text-2xl font-bold text-slate-800">{projections.indicators.paybackMonth} meses</p>
                      </div>
                      <div className="p-4 bg-slate-50 rounded-lg border border-slate-100">
                          <p className="text-xs uppercase font-bold text-slate-400">Investimento Máximo</p>
                          <p className="text-2xl font-bold text-red-600">{formatCurrency(projections.indicators.totalInvestment)}</p>
                      </div>
                  </div>
              </div>
          )}
      </div>

    </div>
  );
};

export default Dashboard;

