import React, { useState, useRef, useEffect, useCallback } from 'react';
import { ProposalData, Role, CanvasSection } from '../types';
import { Plus, Trash2, HardHat, Briefcase, LayoutList, Network, Users, Calculator, GripHorizontal, Search, ZoomIn, ZoomOut, Maximize, X, MousePointer2, Move, SquareDashed, ArrowRight, Zap, Biohazard, Palette, Split, MousePointerClick, LayoutGrid, Copy, Scissors, Check } from 'lucide-react';
