}

// --- CONFIG ---
const CARD_WIDTH = 280;
const CARD_HEIGHT = 160;
const GRID_SIZE = 20;

// --- GEOMETRY UTILS ---

type Point = { x: number; y: number };
type Side = 'top' | 'right' | 'bottom' | 'left';

const getConnectorPosition = (role: Role, side: Side): Point => {
    const x = role.x || 0;
    const y = role.y || 0;

    switch (side) {
        case 'top': return { x: x + CARD_WIDTH / 2, y: y };
        case 'right': return { x: x + CARD_WIDTH, y: y + CARD_HEIGHT / 2 };
        case 'bottom': return { x: x + CARD_WIDTH / 2, y: y + CARD_HEIGHT };
        case 'left': return { x: x, y: y + CARD_HEIGHT / 2 };
    }
};

const getBestConnectionSides = (source: Role, target: Role): { start: Side, end: Side } => {
    const sx = source.x || 0;
    const sy = source.y || 0;
    const tx = target.x || 0;
    const ty = target.y || 0;

    const dx = (tx + CARD_WIDTH/2) - (sx + CARD_WIDTH/2);
    const dy = (ty + CARD_HEIGHT/2) - (sy + CARD_HEIGHT/2);

    // Standard auto-layout logic: prefer Bottom-to-Top for hierarchy
    if (Math.abs(dy) > Math.abs(dx) && dy > 0) {
        return { start: 'bottom', end: 'top' };
    }

    // Otherwise, side-to-side or bottom-to-side
    if (Math.abs(dx) > Math.abs(dy)) {
        return dx > 0 ? { start: 'right', end: 'left' } : { start: 'left', end: 'right' };
    } 

    return { start: 'bottom', end: 'top' }; // Fallback
};

// --- CUSTOM INPUT COMPONENT FOR MONEY ---
const MoneyInput: React.FC<{ 
    value: number; 
    onChange: (val: number) => void; 
    className?: string;
    disabled?: boolean;
}> = ({ value, onChange, className, disabled }) => {
    const [displayValue, setDisplayValue] = useState('');
    const [isFocused, setIsFocused] = useState(false);

    useEffect(() => {
        if (!isFocused) {
            // Format to pt-BR string (e.g. 2.500,00) but without R$ symbol for the input itself if desired, 
            // or just use standard grouping.
            setDisplayValue(new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(value));
        }
    }, [value, isFocused]);

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        // Allow digits and comma
        const raw = e.target.value;
        setDisplayValue(raw);
    };

    const handleBlur = () => {
        setIsFocused(false);
        // Parse "2.500,50" -> 2500.50
        // Remove dots, replace comma with dot
        const cleanStr = displayValue.replace(/\./g, '').replace(',', '.');
        const num = parseFloat(cleanStr);
        if (!isNaN(num)) {
            onChange(num);
        } else {
            // Revert to original if invalid
            setDisplayValue(new Intl.NumberFormat('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 }).format(value));
        }
    };

    return (
        <input
            type="text"
            value={displayValue}
            onChange={handleChange}
            onFocus={() => setIsFocused(true)}
            onBlur={handleBlur}
            className={className}
            disabled={disabled}
            onMouseDown={(e) => e.stopPropagation()}
        />
    );
};


const Team: React.FC<TeamProps> = ({ data, updateData }) => {
  const [viewMode, setViewMode] = useState<'list' | 'canvas' | 'grid'>('grid'); // Default set to GRID

  // Canvas State
  const canvasRef = useRef<HTMLDivElement>(null);
  const [pan, setPan] = useState<Point>({ x: 0, y: 0 });
  const [scale, setScale] = useState(1);

  // Interaction State
  const [isPanning, setIsPanning] = useState(false);
  const [dragState, setDragState] = useState<{
      id: string;
      type: 'role' | 'section';
      startX: number;
      startY: number;
      initialObjX: number;
      initialObjY: number;
  } | null>(null);

  const [lastMousePos, setLastMousePos] = useState<Point>({ x: 0, y: 0 });

  // Connection State
  const [connecting, setConnecting] = useState<{
      sourceId: string;
      sourceSide: Side;
      currentMousePos: Point; 
  } | null>(null);

  // Magnetic Snapping State (Target Port during drag)
  const [snapTarget, setSnapTarget] = useState<{ roleId: string; side: Side } | null>(null);

  // Context Menus & Modals
  const [roleContextMenu, setRoleContextMenu] = useState<{ x: number, y: number, roleId: string } | null>(null);
  const [connectionContextMenu, setConnectionContextMenu] = useState<{ x: number, y: number, childId: string, parentId: string } | null>(null);

  // Split Modal State
  const [splitModal, setSplitModal] = useState<{ roleId: string; maxQty: number } | null>(null);
  const [splitQty, setSplitQty] = useState(1);

  // --- INITIALIZATION ---
  useEffect(() => {
      let hasUpdates = false;
      const newRoles = data.roles.map((r, i) => {
          if (r.x === undefined) {
              hasUpdates = true;
              return { ...r, x: 100 + (i % 3) * 320, y: 100 + Math.floor(i / 3) * 220 };
          }
          return r;
      });
      if (hasUpdates) updateData({ roles: newRoles });
  }, [data.roles]);

  // --- COORDINATE CONVERSION ---
  const screenToWorld = (screenX: number, screenY: number) => {
      const rect = canvasRef.current?.getBoundingClientRect();
      if (!rect) return { x: 0, y: 0 };
      return {
          x: (screenX - rect.left - pan.x) / scale,
          y: (screenY - rect.top - pan.y) / scale
      };
  };

  // --- MOUSE HANDLERS ---

  const handleMouseDown = (e: React.MouseEvent) => {
      if (e.button === 1 || (e.button === 0 && e.shiftKey)) {
          e.preventDefault();
          setIsPanning(true);
          setLastMousePos({ x: e.clientX, y: e.clientY });
          return;
      }

      if (e.target === canvasRef.current || (e.target as HTMLElement).id === 'canvas-bg') {
          setIsPanning(true); 
          setLastMousePos({ x: e.clientX, y: e.clientY });
          setRoleContextMenu(null);
          setConnectionContextMenu(null);
      }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
      if (isPanning) {
          const dx = e.clientX - lastMousePos.x;
          const dy = e.clientY - lastMousePos.y;
          setPan(p => ({ x: p.x + dx, y: p.y + dy }));
          setLastMousePos({ x: e.clientX, y: e.clientY });
          return;
      }

      const worldPos = screenToWorld(e.clientX, e.clientY);

      if (dragState) {
          const dx = (e.clientX - dragState.startX) / scale;
          const dy = (e.clientY - dragState.startY) / scale;

          let newX = dragState.initialObjX + dx;
          let newY = dragState.initialObjY + dy;

          newX = Math.round(newX / GRID_SIZE) * GRID_SIZE;
          newY = Math.round(newY / GRID_SIZE) * GRID_SIZE;

          if (dragState.type === 'role') {
              updateRole(dragState.id, { x: newX, y: newY });
          } else if (dragState.type === 'section') {
              updateSection(dragState.id, { x: newX, y: newY });
          }
      }

      if (connecting) {
          // Update the line tip to mouse position (unless snapped)
          setConnecting(prev => prev ? { ...prev, currentMousePos: worldPos } : null);
      }
  };

  const handleMouseUp = () => {
      setIsPanning(false);
      setDragState(null);

      // If we were connecting and let go NOT on a snap target, cancel
      if (connecting && !snapTarget) {
          setConnecting(null);
      }
  };

  const handleWheel = useCallback((e: WheelEvent) => {
      if (e.ctrlKey || e.metaKey) {
          e.preventDefault();
          const zoomSensitivity = 0.001;
          const newScale = Math.min(Math.max(0.1, scale - e.deltaY * zoomSensitivity), 5);
          setScale(newScale);
      } else {
          setPan(p => ({ x: p.x - e.deltaX, y: p.y - e.deltaY }));
      }
  }, [scale]);

  useEffect(() => {
      const canvas = canvasRef.current;
      if (canvas) {
          canvas.addEventListener('wheel', handleWheel, { passive: false });
          return () => canvas.removeEventListener('wheel', handleWheel);
      }
  }, [handleWheel, viewMode]);

  // --- INTERACTIONS ---

  const startDrag = (e: React.MouseEvent, id: string, type: 'role' | 'section') => {
      e.stopPropagation();
      setRoleContextMenu(null);
      setConnectionContextMenu(null);
      if (e.button !== 0) return; 

      const obj = type === 'role' 
          ? data.roles.find(r => r.id === id)
          : data.sections?.find(s => s.id === id);

      if (!obj) return;

      setDragState({
          id,
          type,
          startX: e.clientX,
          startY: e.clientY,
          initialObjX: obj.x || 0,
          initialObjY: obj.y || 0
      });
  };

  const startConnection = (e: React.MouseEvent, sourceId: string, side: Side) => {
      e.stopPropagation();
      const worldPos = screenToWorld(e.clientX, e.clientY);
      setConnecting({
          sourceId,
          sourceSide: side,
          currentMousePos: worldPos
      });
  };

  const handleSnapEnter = (roleId: string, side: Side) => {
      if (connecting && connecting.sourceId !== roleId) {
          setSnapTarget({ roleId, side });
      }
  };

  const handleSnapLeave = () => {
      setSnapTarget(null);
  };

  const finishConnection = (e: React.MouseEvent, targetId: string) => {
      e.stopPropagation();
      // Ensure we are connecting, and not to self
      if (connecting && connecting.sourceId !== targetId) {
          updateRole(targetId, { parentId: connecting.sourceId });
      }
      setConnecting(null);
      setSnapTarget(null);
  };

  const disconnectRole = (roleId: string) => {
      updateRole(roleId, { parentId: undefined });
      setConnectionContextMenu(null);
  };

  // --- DATA HELPERS ---

  const updateRole = (id: string, updates: Partial<Role>) => {
      const newRoles = data.roles.map(r => r.id === id ? { ...r, ...updates } : r);
      updateData({ roles: newRoles });
  };

  const updateSection = (id: string, updates: Partial<CanvasSection>) => {
      const newSections = (data.sections || []).map(s => s.id === id ? { ...s, ...updates } : s);
      updateData({ sections: newSections });
  };

  const addRole = () => {
      // Position calculation
      let x = 100, y = 100;
      if (viewMode === 'canvas') {
          const rect = canvasRef.current?.getBoundingClientRect();
          x = rect ? (rect.width/2 - pan.x)/scale : 100;
          y = rect ? (rect.height/2 - pan.y)/scale : 100;
      }

      const newRole: Role = {
          id: Math.random().toString(36).substr(2, 9),
          title: 'Novo Cargo',
          category: 'Operational',
          quantity: 1,
          baseSalary: 2500,
          additionalHazard: false,
          additionalDanger: false,
          x: x - CARD_WIDTH/2,
          y: y - CARD_HEIGHT/2,
          color: '#1e293b'
      };
      updateData({ roles: [...data.roles, newRole] });
  };

  const deleteRole = (id: string) => {
      const newRoles = data.roles.filter(r => r.id !== id).map(r => r.parentId === id ? { ...r, parentId: undefined } : r);
      updateData({ roles: newRoles });
  };

  const addSection = () => {
      const rect = canvasRef.current?.getBoundingClientRect();
      const centerX = rect ? (rect.width/2 - pan.x)/scale : 100;
      const centerY = rect ? (rect.height/2 - pan.y)/scale : 100;

      const newSection: CanvasSection = {
          id: Math.random().toString(36).substr(2, 9),
          title: 'ÁREA / SETOR',
          x: centerX - 250,
          y: centerY - 250,
          width: 500,
          height: 500,
          color: '#94a3b8'
      };
      updateData({ sections: [...(data.sections || []), newSection] });
  };

  const removeSection = (id: string) => {
      if(confirm('Remover área?')) {
          updateData({ sections: (data.sections || []).filter(s => s.id !== id) });
      }
  };

  // --- SPLIT LOGIC ---
  const openSplitModal = (role: Role) => {
      if (role.quantity <= 0.5) return; // Cannot split if 0.5 or less
      setSplitModal({ roleId: role.id, maxQty: role.quantity });
      setSplitQty(0.5); // Default start
  };

  const handleSplitConfirm = () => {
      if (!splitModal) return;

      const originalRole = data.roles.find(r => r.id === splitModal.roleId);
      if (!originalRole) return;

      if (splitQty >= originalRole.quantity || splitQty <= 0) {
          alert("Quantidade inválida para divisão.");
          return;
      }

      // 1. Update Original Role
      const newOriginalQty = originalRole.quantity - splitQty;

      // 2. Create New Role (Copy)
      const newRole: Role = {
          ...originalRole,
          id: Math.random().toString(36).substr(2, 9),
          title: `${originalRole.title} (Cópia)`,
          quantity: splitQty,
          x: (originalRole.x || 0) + 40, // Slight visual offset
          y: (originalRole.y || 0) + 40,
      };

      // 3. Apply changes
      const updatedRoles = data.roles.map(r => 
          r.id === originalRole.id ? { ...r, quantity: newOriginalQty } : r
      );
      updateData({ roles: [...updatedRoles, newRole] });

      setSplitModal(null);
  };

  // --- RENDER HELPERS ---

  const renderConnection = (p1: Point, p2: Point, side1: Side, side2: Side, childId?: string, parentId?: string, isTemp = false) => {
      const dist = Math.sqrt(Math.pow(p2.x - p1.x, 2) + Math.pow(p2.y - p1.y, 2));
      const curveStrength = Math.min(dist * 0.5, 150);

      const getCP = (p: Point, s: Side, strength: number): Point => {
          switch(s) {
              case 'top': return { x: p.x, y: p.y - strength };
              case 'bottom': return { x: p.x, y: p.y + strength };
              case 'left': return { x: p.x - strength, y: p.y };
              case 'right': return { x: p.x + strength, y: p.y };
          }
      };

      const cp1 = getCP(p1, side1, curveStrength);
      const cp2 = getCP(p2, side2, curveStrength);

      const path = `M ${p1.x} ${p1.y} C ${cp1.x} ${cp1.y}, ${cp2.x} ${cp2.y}, ${p2.x} ${p2.y}`;

      // Get color based on parent
      const parentRole = parentId ? data.roles.find(r => r.id === parentId) : null;
      const lineColor: string = parentRole?.color || '#64748b'; 

      return (
          <g key={isTemp ? 'temp' : `${parentId}-${childId}`}>
              {/* Hitbox Path (Thick, invisible, for easier clicking) */}
              {!isTemp && childId && parentId && (
                  <path 
                    d={path}
                    stroke="transparent"
                    strokeWidth={20}
                    fill="none"
                    className="cursor-pointer pointer-events-auto"
                    onContextMenu={(e) => {
                        e.preventDefault();
                        e.stopPropagation();
                        setConnectionContextMenu({ x: e.clientX, y: e.clientY, childId, parentId });
                        setRoleContextMenu(null);
                    }}
                    onMouseEnter={(e) => (e.target as SVGElement).nextElementSibling?.setAttribute('stroke-width', '4')}
                    onMouseLeave={(e) => (e.target as SVGElement).nextElementSibling?.setAttribute('stroke-width', '2')}
                  />
              )}

              {/* Visible Path */}
              <path 
                d={path}
                stroke={isTemp ? '#fbbf24' : lineColor}
                strokeWidth={isTemp ? 4 : 2}
                fill="none"
                strokeDasharray={isTemp ? "5,5" : "none"}
                markerEnd={isTemp ? "url(#arrowhead-amber)" : `url(#arrowhead-${lineColor.replace('#','')})`}
                className="pointer-events-none transition-all duration-300"
                strokeLinecap="round"
              />
          </g>
      );
  };

  const calculateRoleTotal = (role: Role) => {
    let base = role.baseSalary;
    if (role.additionalHazard) base += role.baseSalary * 0.20;
    if (role.additionalDanger) base += role.baseSalary * 0.30;
    return base * role.quantity;
  };
  const totalMonthly = data.roles.reduce((acc, r) => acc + calculateRoleTotal(r), 0);
  const totalHC = data.roles.reduce((acc, r) => acc + r.quantity, 0);

  // Generate dynamic markers for all used colors
  const uniqueColors: string[] = Array.from(new Set(data.roles.map(r => r.color || '#1e293b')));
  uniqueColors.push('#64748b'); // Default

  // Common Card Render (Used in Canvas and Grid)
  const renderCard = (role: Role, mode: 'canvas' | 'grid') => {
      const isOps = role.category === 'Operational';
      const isConnectingTarget = mode === 'canvas' && connecting && connecting.sourceId !== role.id;
      const isSnapped = mode === 'canvas' && snapTarget?.roleId === role.id;

      return (
          <div
            key={role.id}
            className={`
                rounded-lg shadow-sm border border-slate-300 bg-white group transition-all duration-200 flex flex-col
                ${mode === 'canvas' ? 'absolute z-10' : 'relative h-full'}
                ${mode === 'canvas' && connecting ? (isConnectingTarget ? (isSnapped ? 'ring-4 ring-[#fbbf24] shadow-2xl scale-105' : 'opacity-80') : 'opacity-30 pointer-events-none') : 'hover:shadow-lg'}
            `}
            style={{ 
                left: mode === 'canvas' ? role.x : undefined, 
                top: mode === 'canvas' ? role.y : undefined, 
                width: mode === 'canvas' ? CARD_WIDTH : '100%', 
                height: mode === 'canvas' ? CARD_HEIGHT : 'auto',
                minHeight: mode === 'grid' ? 170 : undefined
            }}
            onMouseUp={(e) => mode === 'canvas' && connecting ? finishConnection(e, role.id) : null}
            onContextMenu={(e) => { 
                if (mode === 'canvas') {
                    e.stopPropagation(); 
                    e.preventDefault(); 
                    setRoleContextMenu({ x: e.clientX, y: e.clientY, roleId: role.id });
                    setConnectionContextMenu(null);
                }
            }}
          >
              {/* Card Header */}
              <div 
                className={`h-10 px-3 flex items-center justify-between rounded-t-lg border-b border-white/10 ${mode === 'canvas' ? 'cursor-grab active:cursor-grabbing' : ''}`}
                style={{ backgroundColor: role.color || '#1e293b' }}
                onMouseDown={(e) => mode === 'canvas' ? startDrag(e, role.id, 'role') : null}
              >
                  <div className="flex items-center gap-2 text-white/90">
                      {isOps ? <HardHat size={14}/> : <Briefcase size={14}/>}
                      <input 
                        value={role.title}
                        onChange={(e) => updateRole(role.id, { title: e.target.value })}
                        onMouseDown={(e) => e.stopPropagation()} 
                        className="bg-transparent text-white font-bold text-xs uppercase tracking-wide outline-none w-full placeholder-white/50"
                        placeholder="Nome do Cargo"
                      />
                  </div>
                  {mode === 'canvas' ? (
                      <GripHorizontal className="text-white/20" size={14} />
                  ) : (
                      <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                          {role.quantity > 0.5 && (
                              <button onClick={() => openSplitModal(role)} className="p-1 hover:bg-white/20 rounded text-white" title="Dividir Cargo"><Scissors size={12}/></button>
                          )}
                          <button onClick={() => deleteRole(role.id)} className="p-1 hover:bg-red-500/80 rounded text-white" title="Remover"><Trash2 size={12}/></button>
                      </div>
                  )}
              </div>

              {/* Card Body */}
              <div className="flex-1 p-3 bg-white rounded-b-lg flex flex-col justify-between relative text-xs">

                  <div className="flex gap-2 mb-1">
                      <div className="flex-1">
                          <label className="text-[9px] font-bold text-slate-400 uppercase block mb-0.5">Qtd (HC)</label>
                          <div className="flex items-center bg-slate-50 border border-slate-200 rounded px-2 py-1">
                              <Users size={12} className="text-slate-400 mr-1.5 shrink-0"/>
                              <input 
                                type="number" 
                                min="0.5" step="0.5"
                                value={role.quantity} 
                                onChange={(e) => updateRole(role.id, { quantity: parseFloat(e.target.value)||0 })}
                                onMouseDown={(e) => e.stopPropagation()}
                                className="w-full bg-transparent font-bold text-slate-700 outline-none p-0"
                              />
                          </div>
                      </div>
                      <div className="flex-[1.5]">
                          <label className="text-[9px] font-bold text-slate-400 uppercase block mb-0.5">Salário Base</label>
                          <div className="flex items-center bg-slate-50 border border-slate-200 rounded px-2 py-1">
                              <span className="text-[10px] text-slate-400 mr-1">R$</span>
                              <MoneyInput 
                                value={role.baseSalary}
                                onChange={(val) => updateRole(role.id, { baseSalary: val })}
                                className="w-full bg-transparent font-bold text-slate-700 outline-none p-0"
                              />
                          </div>
                      </div>
                  </div>

                  <div className="flex gap-1 mb-2">
                      <button 
                        onClick={(e) => { e.stopPropagation(); updateRole(role.id, { additionalHazard: !role.additionalHazard }); }}
                        className={`flex-1 flex items-center justify-center gap-1 py-1.5 rounded border text-[9px] font-bold transition-all ${role.additionalHazard ? 'bg-orange-50 border-orange-200 text-orange-700' : 'bg-white border-slate-100 text-slate-300 hover:border-slate-200'}`}
                        title="Adicional de Insalubridade (+20%)"
                        onMouseDown={(e) => e.stopPropagation()}
                      >
                          <Biohazard size={12} /> +20%
                      </button>
                      <button 
                        onClick={(e) => { e.stopPropagation(); updateRole(role.id, { additionalDanger: !role.additionalDanger }); }}
                        className={`flex-1 flex items-center justify-center gap-1 py-1.5 rounded border text-[9px] font-bold transition-all ${role.additionalDanger ? 'bg-red-50 border-red-200 text-red-700' : 'bg-white border-slate-100 text-slate-300 hover:border-slate-200'}`}
                        title="Adicional de Periculosidade (+30%)"
                        onMouseDown={(e) => e.stopPropagation()}
                      >
                          <Zap size={12} /> +30%
                      </button>
                  </div>

                  <div className="pt-2 border-t border-slate-100 flex justify-between items-center">
                      <div className="flex items-center gap-2">
                          <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider">Total</span>
                          {/* Split Button on Canvas Mode (Since it's not in header) */}
                          {mode === 'canvas' && role.quantity > 0.5 && (
                              <button 
                                onClick={(e) => { e.stopPropagation(); openSplitModal(role); }}
                                className="text-slate-300 hover:text-blue-600 transition-colors"
                                title="Dividir / Separar Cargo"
                                onMouseDown={(e) => e.stopPropagation()}
                              >
                                  <Scissors size={12} />
                              </button>
                          )}
                      </div>
                      <span className="text-sm font-black text-slate-800">{formatCurrency(calculateRoleTotal(role))}</span>
                  </div>
              </div>

              {/* PORTS FOR CANVAS ONLY */}
              {mode === 'canvas' && (
                  <>
                      {/* TOP */}
                      <div 
                          className={`absolute -top-3 left-1/2 -translate-x-1/2 w-8 h-8 flex items-center justify-center z-20 cursor-crosshair transition-opacity ${connecting || isConnectingTarget ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}
                          onMouseDown={(e) => startConnection(e, role.id, 'top')}
                          onMouseEnter={() => handleSnapEnter(role.id, 'top')}
                          onMouseLeave={handleSnapLeave}
                      >
                          <div className={`w-3 h-3 bg-white border-2 rounded-full shadow-sm transition-transform ${snapTarget?.roleId === role.id && snapTarget?.side === 'top' ? 'bg-[#fbbf24] border-[#fbbf24] scale-150' : 'border-slate-400 hover:bg-[#fbbf24] hover:border-[#fbbf24]'}`}></div>
                      </div>
                      {/* BOTTOM */}
                      <div 
                          className={`absolute -bottom-3 left-1/2 -translate-x-1/2 w-8 h-8 flex items-center justify-center z-20 cursor-crosshair transition-opacity ${connecting || isConnectingTarget ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}
                          onMouseDown={(e) => startConnection(e, role.id, 'bottom')}
                          onMouseEnter={() => handleSnapEnter(role.id, 'bottom')}
                          onMouseLeave={handleSnapLeave}
                      >
                          <div className={`w-3 h-3 bg-white border-2 rounded-full shadow-sm transition-transform ${snapTarget?.roleId === role.id && snapTarget?.side === 'bottom' ? 'bg-[#fbbf24] border-[#fbbf24] scale-150' : 'border-slate-400 hover:bg-[#fbbf24] hover:border-[#fbbf24]'}`}></div>
                      </div>
                      {/* LEFT */}
                      <div 
                          className={`absolute top-1/2 -left-3 -translate-y-1/2 w-8 h-8 flex items-center justify-center z-20 cursor-crosshair transition-opacity ${connecting || isConnectingTarget ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}
                          onMouseDown={(e) => startConnection(e, role.id, 'left')}
                          onMouseEnter={() => handleSnapEnter(role.id, 'left')}
                          onMouseLeave={handleSnapLeave}
                      >
                          <div className={`w-3 h-3 bg-white border-2 rounded-full shadow-sm transition-transform ${snapTarget?.roleId === role.id && snapTarget?.side === 'left' ? 'bg-[#fbbf24] border-[#fbbf24] scale-150' : 'border-slate-400 hover:bg-[#fbbf24] hover:border-[#fbbf24]'}`}></div>
                      </div>
                      {/* RIGHT */}
                      <div 
                          className={`absolute top-1/2 -right-3 -translate-y-1/2 w-8 h-8 flex items-center justify-center z-20 cursor-crosshair transition-opacity ${connecting || isConnectingTarget ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'}`}
                          onMouseDown={(e) => startConnection(e, role.id, 'right')}
                          onMouseEnter={() => handleSnapEnter(role.id, 'right')}
                          onMouseLeave={handleSnapLeave}
                      >
                          <div className={`w-3 h-3 bg-white border-2 rounded-full shadow-sm transition-transform ${snapTarget?.roleId === role.id && snapTarget?.side === 'right' ? 'bg-[#fbbf24] border-[#fbbf24] scale-150' : 'border-slate-400 hover:bg-[#fbbf24] hover:border-[#fbbf24]'}`}></div>
                      </div>
                  </>
              )}
          </div>
      );
  }

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] bg-[#f8fafc] overflow-hidden relative">

      {/* HEADER OVERLAY */}
      <div className="absolute top-0 left-0 right-0 z-30 p-6 pointer-events-none flex justify-between items-start bg-gradient-to-b from-slate-100/90 to-transparent backdrop-blur-[2px]">
          <div className="pointer-events-auto">
              <h2 className="text-2xl font-black text-slate-900 tracking-tight">Estrutura Organizacional</h2>
              <p className="text-slate-500 text-sm font-medium">Organize a equipe visualmente. Custo não é afetado pelas áreas (Canvas).</p>
          </div>

          <div className="flex gap-3 pointer-events-auto">
              <div className="bg-white p-1 rounded-lg border border-slate-200 shadow-xl flex items-center">
                  <button onClick={() => setViewMode('grid')} className={`p-2 rounded-md transition-all ${viewMode==='grid'?'bg-[#0f172a] text-white shadow-md':'text-slate-400 hover:text-slate-600'}`} title="Cards"><LayoutGrid size={18}/></button>
                  <button onClick={() => setViewMode('canvas')} className={`p-2 rounded-md transition-all ${viewMode==='canvas'?'bg-[#0f172a] text-white shadow-md':'text-slate-400 hover:text-slate-600'}`} title="Organograma"><Network size={18}/></button>
                  <button onClick={() => setViewMode('list')} className={`p-2 rounded-md transition-all ${viewMode==='list'?'bg-[#0f172a] text-white shadow-md':'text-slate-400 hover:text-slate-600'}`} title="Lista"><LayoutList size={18}/></button>
              </div>
              {viewMode === 'canvas' && (
                  <button onClick={addSection} className="bg-white text-slate-600 px-4 py-2.5 rounded-lg text-xs font-bold border border-slate-200 shadow-xl hover:bg-slate-50 transition-all flex items-center gap-2">
                      <SquareDashed size={16} /> Nova Área
                  </button>
              )}
              <button onClick={addRole} className="bg-[#0f172a] text-white px-5 py-2.5 rounded-lg text-xs font-bold shadow-xl shadow-slate-900/20 hover:bg-[#1e293b] transition-all flex items-center gap-2 active:scale-95">
                  <Plus size={16} /> Novo Cargo
              </button>
          </div>
      </div>

      {/* CANVAS VIEW */}
      {viewMode === 'canvas' && (
          <div 
            ref={canvasRef}
            id="canvas-bg"
            className="flex-1 w-full h-full relative bg-slate-100 overflow-hidden cursor-grab active:cursor-grabbing select-none"
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onContextMenu={(e) => e.preventDefault()}
          >
              {/* Infinite Grid */}
              <div 
                className="absolute inset-0 pointer-events-none opacity-10"
                style={{
                    backgroundImage: 'radial-gradient(#0f172a 1.5px, transparent 1.5px)',
                    backgroundSize: `${GRID_SIZE * scale}px ${GRID_SIZE * scale}px`,
                    backgroundPosition: `${pan.x}px ${pan.y}px`
                }}
              />

              {/* WORLD TRANSFORM LAYER */}
              <div 
                className="absolute top-0 left-0 w-full h-full origin-top-left"
                style={{ transform: `translate(${pan.x}px, ${pan.y}px) scale(${scale})` }}
              >

                  {/* LAYER 0: SECTIONS (Bottom) */}
                  {(data.sections || []).map(section => (
                      <div
                        key={section.id}
                        className="absolute border-2 border-dashed rounded-xl group/section"
                        style={{
                            left: section.x, top: section.y,
                            width: section.width, height: section.height,
                            borderColor: section.color,
                            backgroundColor: section.color + '15', 
                            zIndex: 0
                        }}
                        onMouseDown={(e) => startDrag(e, section.id, 'section')}
                      >
                          <input 
                            value={section.title}
                            onChange={(e) => updateSection(section.id, { title: e.target.value })}
                            onMouseDown={(e) => e.stopPropagation()} 
                            className="bg-transparent font-black text-2xl uppercase p-4 w-full outline-none"
                            style={{ color: section.color }}
                          />
                          <button 
                            onClick={(e) => {e.stopPropagation(); removeSection(section.id);}} 
                            className="absolute top-2 right-2 p-1 text-slate-300 hover:text-red-500 opacity-0 group-hover/section:opacity-100 transition-opacity"
                          >
                              <Trash2 size={16}/>
                          </button>

                          <div className="absolute bottom-0 right-0 w-8 h-8 cursor-nwse-resize flex items-end justify-end p-1">
                              <div className="w-3 h-3 border-r-2 border-b-2" style={{ borderColor: section.color }}></div>
                          </div>
                      </div>
                  ))}

                  {/* LAYER 1: CONNECTIONS */}
                  <svg className="absolute top-0 left-0 overflow-visible pointer-events-none" style={{ width: 1, height: 1, zIndex: 1 }}>
                      <defs>
                          <marker id="arrowhead-amber" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto"><polygon points="0 0, 10 3.5, 0 7" fill="#fbbf24" /></marker>
                          {uniqueColors.map(c => (
                              <marker key={c} id={`arrowhead-${c.replace('#','')}`} markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
                                  <polygon points="0 0, 10 3.5, 0 7" fill={c} />
                              </marker>
                          ))}
                      </defs>
                      {/* Existing Connections */}
                      {data.roles.map(role => {
                          if (!role.parentId) return null;
                          const parent = data.roles.find(r => r.id === role.parentId);
                          if (!parent) return null;

                          const { start: startSide, end: endSide } = getBestConnectionSides(parent, role);
                          const p1 = getConnectorPosition(parent, startSide);
                          const p2 = getConnectorPosition(role, endSide);

                          return renderConnection(p1, p2, startSide, endSide, role.id, parent.id);
                      })}

                      {/* Active Dragging Connection with Snapping */}
                      {connecting && (
                          (() => {
                              const source = data.roles.find(r => r.id === connecting.sourceId);
                              if (!source) return null;

                              const p1 = getConnectorPosition(source, connecting.sourceSide);

                              let p2 = connecting.currentMousePos;
                              let targetSide: Side = connecting.sourceSide === 'bottom' ? 'top' : 'left'; // Default

                              // If snapped, use the snapped target's specific position
                              if (snapTarget) {
                                  const targetRole = data.roles.find(r => r.id === snapTarget.roleId);
                                  if (targetRole) {
                                      p2 = getConnectorPosition(targetRole, snapTarget.side);
                                      targetSide = snapTarget.side;
                                  }
                              }

                              return renderConnection(p1, p2, connecting.sourceSide, targetSide, undefined, undefined, true);
                          })()
                      )}
                  </svg>

