            <div className="relative group/palette">
                <button 
                    className="p-1.5 bg-white/90 backdrop-blur-sm hover:bg-white text-slate-400 hover:text-slate-600 rounded-md shadow-sm border border-slate-200 transition-all"
                    onMouseDown={(e) => e.stopPropagation()}
                    title="Alterar Cor"
                >
                    <Palette size={14}/>
                </button>
                <div className="absolute right-0 top-full mt-2 p-2 bg-white rounded-lg shadow-xl border border-slate-200 grid grid-cols-4 gap-2 w-max hidden group-hover/palette:grid z-50" onMouseDown={(e) => e.stopPropagation()}>
                    {[
                        '#94a3b8', '#64748b', '#ef4444', '#f97316',
                        '#f59e0b', '#84cc16', '#10b981', '#06b6d4',
                        '#3b82f6', '#6366f1', '#8b5cf6', '#d946ef'
                    ].map((c) => (
                        <button
                            key={c}
                            onClick={() => updateSection(section.id, { color: c })}
                            className={`w-5 h-5 rounded-full border hover:scale-110 transition-transform shadow-sm ${section.color === c ? 'border-slate-900 ring-1 ring-slate-300' : 'border-slate-100'}`}
                            style={{ backgroundColor: c }}
                        />
                    ))}
                </div>
            </div>

            <button 
              onClick={(e) => {e.stopPropagation(); removeSection(section.id);}} 
              className="p-1.5 bg-white/90 backdrop-blur-sm hover:bg-white text-slate-400 hover:text-red-500 rounded-md shadow-sm border border-slate-200 transition-all"
              onMouseDown={(e) => e.stopPropagation()}
              title="Remover Área"
            >
                <Trash2 size={14}/>
            </button>
        </div>

        {/* RESIZE HANDLES (8 Directions) */}
        {['nw', 'n', 'ne', 'e', 'se', 's', 'sw', 'w'].map(handle => {

import React, { useState } from 'react';
import { ProposalData, Role } from '../types';
import { formatCurrency, formatPercent } from '../utils/pricingEngine';
import { Users, Plus, Trash2, ShieldAlert, DollarSign, Briefcase, UserPlus, Info, LayoutList, LayoutGrid, CheckSquare, Square, AlertCircle, HardHat } from 'lucide-react';

interface TeamProps {
  data: ProposalData;
  updateData: (newData: Partial<ProposalData>) => void;
}

const Team: React.FC<TeamProps> = ({ data, updateData }) => {
  const [viewMode, setViewMode] = useState<'list' | 'grid'>('list');

  // --- Logic ---
  const addRole = (category: 'Operational' | 'Administrative') => {
    const newRole: Role = {
      id: Math.random().toString(36).substr(2, 9),
      title: category === 'Operational' ? 'Novo Técnico' : 'Novo Analista',
      category,
      quantity: 1,
      baseSalary: 2000,
      additionalHazard: category === 'Operational', // Default true for Ops
      additionalDanger: false,
    };
    updateData({ roles: [...data.roles, newRole] });
  };

  const updateRole = (id: string, field: keyof Role, value: any) => {
    const updatedRoles = data.roles.map(r => r.id === id ? { ...r, [field]: value } : r);
    updateData({ roles: updatedRoles });
  };

  const removeRole = (id: string) => {
    if (confirm('Remover este cargo?')) {
        updateData({ roles: data.roles.filter(r => r.id !== id) });
    }
  };

  const calculateRoleCost = (role: Role) => {
     let base = role.baseSalary;
     let addOns = 0;
     if (role.additionalHazard) addOns += role.baseSalary * 0.20;
     if (role.additionalDanger) addOns += role.baseSalary * 0.30;

     const totalBase = base + addOns;
     // Encargos sobre o total base (salário + adicionais)
     const charges = totalBase * data.taxConfig.socialChargesRate;
     return (totalBase + charges) * role.quantity;
  };

  const totalHeadcount = data.roles.reduce((acc, r) => acc + r.quantity, 0);
  const totalMonthlyLabor = data.roles.reduce((acc, r) => acc + calculateRoleCost(r), 0);

  const categories = [
      { id: 'Operational', label: 'Equipe Operacional', icon: HardHat, color: 'text-blue-600', bg: 'bg-blue-50', border: 'border-blue-200' },
      { id: 'Administrative', label: 'Equipe Administrativa', icon: Briefcase, color: 'text-slate-600', bg: 'bg-slate-50', border: 'border-slate-200' }
  ] as const;

  return (
    <div className="p-8 space-y-6 max-w-[1600px] mx-auto">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-slate-200 pb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
             <Users size={28} className="text-[#0f172a]" />
             Quadro de Pessoal (Headcount)
          </h2>
          <p className="text-slate-500 text-sm mt-1">Definição de cargos, salários e adicionais trabalhistas.</p>
        </div>

        <div className="flex bg-slate-100 p-1 rounded-lg">
            <button 
              onClick={() => setViewMode('list')}
              className={`p-2 rounded-md transition-all ${viewMode === 'list' ? 'bg-slate-100 text-[#0f172a] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
              title="Lista"
            >
              <LayoutList size={20} />
            </button>
            <button 
              onClick={() => setViewMode('grid')}
              className={`p-2 rounded-md transition-all ${viewMode === 'grid' ? 'bg-slate-100 text-[#0f172a] shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
              title="Cards"
            >
              <LayoutGrid size={20} />
            </button>
        </div>
      </header>

      <div className="flex flex-col xl:flex-row gap-8 items-start">

          {/* LEFT: ROLES LISTS */}
          <div className="flex-1 w-full space-y-8">
              {categories.map(cat => {
                  const roles = data.roles.filter(r => r.category === cat.id);
                  const Icon = cat.icon;
                  return (
                      <div key={cat.id} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
                          <div className="p-4 border-b border-slate-100 bg-slate-50/50 flex justify-between items-center">
                              <div className="flex items-center gap-3">
                                  <div className={`p-2 rounded-lg ${cat.bg} ${cat.color} border ${cat.border}`}>
                                      <Icon size={20} />
                                  </div>
                                  <div>
                                      <h3 className="font-bold text-slate-800 text-base">{cat.label}</h3>
                                      <p className="text-[10px] text-slate-500">{roles.length} cargos definidos</p>
                                  </div>
                              </div>
                              <button 
                                onClick={() => addRole(cat.id as any)}
                                className="text-xs font-bold bg-[#0f172a] text-white px-3 py-1.5 rounded-lg flex items-center gap-2 hover:bg-[#1e293b]"
                              >
                                  <Plus size={14} /> Adicionar Cargo
                              </button>
                          </div>

                          <div className="p-0">
                              {viewMode === 'list' ? (
                                  <table className="w-full text-sm text-left">
                                      <thead className="bg-white text-slate-400 font-bold uppercase text-[10px] tracking-wider border-b border-slate-100">
                                          <tr>
                                              <th className="px-6 py-3">Cargo / Função</th>
                                              <th className="px-4 py-3 w-24 text-center">Qtd</th>
                                              <th className="px-4 py-3">Salário Base</th>
                                              <th className="px-4 py-3">Adicionais</th>
                                              <th className="px-6 py-3 text-right">Custo Total</th>
                                              <th className="px-4 py-3 w-10"></th>
                                          </tr>
                                      </thead>
                                      <tbody className="divide-y divide-slate-100">
                                          {roles.map(role => {
                                              const cost = calculateRoleCost(role);
                                              return (
                                                  <tr key={role.id} className="hover:bg-slate-50/50 group">
                                                      <td className="px-6 py-3">
                                                          <input 
                                                              type="text" 
                                                              value={role.title} 
                                                              onChange={(e) => updateRole(role.id, 'title', e.target.value)}
                                                              className="w-full bg-transparent border-none font-bold text-slate-700 p-0 focus:ring-0 placeholder-slate-300"
                                                              placeholder="Nome do cargo"
                                                          />
                                                      </td>
                                                      <td className="px-4 py-3">
                                                          <input 
                                                              type="number" 
                                                              min="0"
                                                              step="0.5"
                                                              value={role.quantity} 
                                                              onChange={(e) => updateRole(role.id, 'quantity', parseFloat(e.target.value) || 0)}
                                                              className="w-full text-center bg-slate-50 border border-slate-200 rounded font-bold text-slate-800 p-1 focus:border-[#fbbf24] outline-none"
                                                          />
                                                      </td>
                                                      <td className="px-4 py-3">
                                                          <div className="flex items-center gap-1">
                                                              <span className="text-[10px] text-slate-400 font-bold">R$</span>
                                                              <input 
                                                                  type="number" 
                                                                  value={role.baseSalary} 
                                                                  onChange={(e) => updateRole(role.id, 'baseSalary', parseFloat(e.target.value) || 0)}
                                                                  className="w-24 bg-transparent border-none font-bold text-slate-700 p-0 focus:ring-0 text-right"
                                                              />
                                                          </div>
                                                      </td>
                                                      <td className="px-4 py-3">
                                                          <div className="flex gap-2">
                                                              <button 
                                                                onClick={() => updateRole(role.id, 'additionalHazard', !role.additionalHazard)}
                                                                className={`px-2 py-1 rounded text-[10px] font-bold border transition-colors ${role.additionalHazard ? 'bg-orange-50 border-orange-200 text-orange-700' : 'bg-slate-50 border-slate-200 text-slate-400 opacity-60 hover:opacity-100'}`}
                                                                title="Insalubridade (20%)"
                                                              >
                                                                  20% INS
                                                              </button>
                                                              <button 
                                                                onClick={() => updateRole(role.id, 'additionalDanger', !role.additionalDanger)}
                                                                className={`px-2 py-1 rounded text-[10px] font-bold border transition-colors ${role.additionalDanger ? 'bg-red-50 border-red-200 text-red-700' : 'bg-slate-50 border-slate-200 text-slate-400 opacity-60 hover:opacity-100'}`}
                                                                title="Periculosidade (30%)"
                                                              >
                                                                  30% PER
                                                              </button>
                                                          </div>
                                                      </td>
                                                      <td className="px-6 py-3 text-right font-bold text-slate-700">
                                                          {formatCurrency(cost)}
                                                      </td>
                                                      <td className="px-4 py-3 text-center">
                                                          <button onClick={() => removeRole(role.id)} className="text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                                                              <Trash2 size={16} />
                                                          </button>
                                                      </td>
                                                  </tr>
                                              );
                                          })}
                                          {roles.length === 0 && (
                                              <tr>
                                                  <td colSpan={6} className="py-8 text-center text-slate-400 italic text-xs">Nenhum cargo nesta categoria.</td>
                                              </tr>
                                          )}
                                      </tbody>
                                  </table>
                              ) : (
                                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 p-4">
                                      {roles.map(role => (
                                          <div key={role.id} className="border border-slate-200 rounded-xl p-4 relative group hover:shadow-md transition-all bg-white">
                                              <button onClick={() => removeRole(role.id)} className="absolute top-3 right-3 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                                                  <Trash2 size={16} />
                                              </button>

                                              <div className="mb-3">
                                                  <label className="text-[9px] font-bold text-slate-400 uppercase">Cargo</label>
                                                  <input 
                                                      type="text" 
                                                      value={role.title} 
                                                      onChange={(e) => updateRole(role.id, 'title', e.target.value)}
                                                      className="w-full text-base font-bold text-slate-800 bg-transparent border-none p-0 focus:ring-0 placeholder-slate-300"
                                                  />
                                              </div>

                                              <div className="grid grid-cols-2 gap-4 mb-4">
                                                  <div>
                                                      <label className="text-[9px] font-bold text-slate-400 uppercase">Salário Base</label>
                                                      <div className="flex items-center gap-1">
                                                          <span className="text-xs text-slate-400">R$</span>
                                                          <input 
                                                              type="number" 
                                                              value={role.baseSalary} 
                                                              onChange={(e) => updateRole(role.id, 'baseSalary', parseFloat(e.target.value) || 0)}
                                                              className="w-full font-bold text-slate-700 bg-transparent border-none p-0 focus:ring-0"
                                                          />
                                                      </div>
                                                  </div>
                                                  <div>
                                                      <label className="text-[9px] font-bold text-slate-400 uppercase">Quantidade</label>
                                                      <input 
                                                          type="number" 
                                                          step="0.5"
                                                          value={role.quantity} 
                                                          onChange={(e) => updateRole(role.id, 'quantity', parseFloat(e.target.value) || 0)}
                                                          className="w-full font-bold text-slate-700 bg-transparent border-none p-0 focus:ring-0"
                                                      />
                                                  </div>
                                              </div>

                                              <div className="flex gap-2 mb-4">
                                                  <button 
                                                    onClick={() => updateRole(role.id, 'additionalHazard', !role.additionalHazard)}
                                                    className={`flex-1 py-1.5 rounded text-[10px] font-bold border transition-colors flex items-center justify-center gap-1 ${role.additionalHazard ? 'bg-orange-50 border-orange-200 text-orange-700' : 'bg-slate-50 border-slate-200 text-slate-400'}`}
                                                  >
                                                      {role.additionalHazard && <CheckSquare size={12}/>} Insalubridade
                                                  </button>
                                                  <button 
                                                    onClick={() => updateRole(role.id, 'additionalDanger', !role.additionalDanger)}
                                                    className={`flex-1 py-1.5 rounded text-[10px] font-bold border transition-colors flex items-center justify-center gap-1 ${role.additionalDanger ? 'bg-red-50 border-red-200 text-red-700' : 'bg-slate-50 border-slate-200 text-slate-400'}`}
                                                  >
                                                      {role.additionalDanger && <CheckSquare size={12}/>} Periculosidade
                                                  </button>
                                              </div>

                                              <div className="pt-3 border-t border-slate-100 flex justify-between items-center">
                                                  <span className="text-xs text-slate-500">Custo Total / Mês</span>
                                                  <span className="font-bold text-slate-800">{formatCurrency(calculateRoleCost(role))}</span>
                                              </div>
                                          </div>
                                      ))}
                                      {roles.length === 0 && (
                                          <div className="col-span-2 text-center py-6 text-slate-400 italic text-xs">Nenhum cargo definido.</div>
                                      )}
                                  </div>
                              )}
                          </div>
                      </div>
                  );
              })}
          </div>

          {/* RIGHT: SUMMARY CARD */}
          <div className="w-full xl:w-80 space-y-4 shrink-0">
               <div className="bg-[#0f172a] rounded-xl p-6 text-white shadow-xl shadow-slate-900/10 relative overflow-hidden">
                  <div className="relative z-10">
                      <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">Folha de Pagamento Total</p>
                      <h3 className="text-3xl font-bold text-[#fbbf24] mb-4">{formatCurrency(totalMonthlyLabor)}</h3>

                      <div className="h-px bg-white/10 w-full mb-4"></div>

                      <div className="flex justify-between items-center mb-2">
                          <span className="text-xs text-slate-400">Headcount (HC)</span>
                          <span className="text-sm font-bold text-slate-200">{totalHeadcount} pessoas</span>
                      </div>
                      <div className="flex justify-between items-center">
                          <span className="text-xs text-slate-400">Encargos Sociais</span>
                          <span className="text-sm font-bold text-emerald-400">{formatPercent(data.taxConfig.socialChargesRate)}</span>
                      </div>
                  </div>
               </div>

               <div className="bg-white rounded-xl border border-slate-200 p-6 shadow-sm">
                   <h4 className="font-bold text-slate-800 text-sm flex items-center gap-2 mb-3">
                       <Info size={16} className="text-slate-400" />
                       Detalhes dos Adicionais
                   </h4>
                   <div className="space-y-3 text-xs text-slate-600">
                       <div className="flex justify-between">
                           <span>Insalubridade</span>
                           <span className="font-bold">20% s/ Salário</span>
                       </div>
                       <div className="flex justify-between">
                           <span>Periculosidade</span>
                           <span className="font-bold">30% s/ Salário</span>
                       </div>
                       <div className="pt-3 border-t border-slate-100 text-[10px] text-slate-400 leading-tight">
                           *Adicionais incidem sobre o salário base e também sofrem incidência de encargos sociais.
                       </div>
                   </div>
               </div>
          </div>

      </div>
    </div>
  );
};

export default Team;
